from __future__ import annotations

import abc
from collections import defaultdict
from copy import deepcopy
from pathlib import Path
from types import TracebackType
from typing import (
    Iterable,
    Union,
    List,
    Dict,
    Any,
    Optional,
    Sequence,
    BinaryIO,
    Type,
    overload,
)

import numpy as np
import numpy.typing as npt
from typing_extensions import Annotated, Literal, Self

from geosat.cloud.exceptions import (
    FieldAlreadyExists,
    InvalidFieldName,
    EmptyPointCloudException,
    HeterogeneousFieldsException,
)
from geosat.cloud.metadata.base_namespace import Metadata
from geosat.cloud.metadata.private_namespace import PrivateNamespace

PathLike = Union[str, Path]
Point3D = Annotated[Sequence[float], 3]


class Reader(abc.ABC):
    """An interface that describes methods to read :class:`PointCloud` objects"""

    @abc.abstractmethod
    def read(self, n: int = -1) -> PointCloud:
        """Shall read n point and return them in a new PointCloud
        if n is less than 0 then all remaining points shall be read
        """

    @abc.abstractmethod
    def close(self) -> None:
        """Should close the reader"""

    @abc.abstractmethod
    def header(self) -> Any:
        """Should return a struct that gives metadata info
        such as point_count, mins, maxs.
        """
        # Note: No choice was made to specify the interface
        # that the returned header should provide. It will
        # be needed if another format is implemented.
        # But as it did not happen in 3+years no choice was made yet
        # #YAGNI

    @classmethod
    @abc.abstractmethod
    def from_source(cls, source: BinaryIO) -> Self:
        """Instantiate the :class:`Reader` from a binary stream

        :param: source: The binary stream the :class:`Reader` should
            be instantiated from. Will be closed once the reader is closed.
        :return: The corresponding instance
        """

    def __enter__(self) -> Self:
        return self

    def __exit__(
        self,
        exc_type: Type[BaseException] | None,
        exc_val: BaseException | None,
        exc_tb: TracebackType | None,
    ) -> None:
        self.close()


class Writer(abc.ABC):
    """An interface that describes methods to write :class:`PointCloud` objects"""

    @abc.abstractmethod
    def write(self, point_cloud: PointCloud) -> None:
        """Should write the point_cloud
        Calling multiple times, the write method is intended
        """

    @abc.abstractmethod
    def close(self) -> None:
        """Should close the writer"""

    @classmethod
    @abc.abstractmethod
    def from_dest(cls, dest: BinaryIO) -> Self:
        """Instantiate the :class:`Writer` from a binary stream

        :param: dest: The binary stream the :class:`Writer` should be instantiated
            from. Will be closed once the writer is closed.
        :return: The corresponding instance
        """

    def __enter__(self) -> Self:
        return self

    def __exit__(
        self,
        exc_type: Type[BaseException] | None,
        exc_val: BaseException | None,
        exc_tb: TracebackType | None,
    ) -> None:
        self.close()


class PointCloud:
    """The class representing a 3D point cloud.

    Coordinates are stored in the `coords` attributes as numpy array of
    shape (num_points, 3).

    Additional fields (such as classification, intensity, etc.) are stored in
    the `fields` attribute. However, this class defines a way to access these
    conveniently as is they were regular class attributes.

    PointClouds may have metadata associated to them (eg: spatial reference system,
    origin path). Metadata are stored in the metadata dict.

    :Examples:

    >>> cloud = PointCloud.read_from_path("tests/data/cloud.laz")
    >>> len(cloud)
    28185
    >>> cloud.coords.shape
    (28185, 3)
    >>> bool(np.all(cloud.classification == cloud.fields["classification"]))
    True
    >>> cloud.metadata["filepath"]
    'tests/data/cloud.laz'
    """

    def __init__(
        self,
        coords: Iterable[Point3D],
        fields: Optional[Dict[str, np.ndarray]] = None,
        metadata: Optional[Metadata] = None,
    ) -> None:
        self.fields: Dict[str, np.ndarray] = {} if fields is None else fields
        self.metadata: Metadata = (
            Metadata(geosat=PrivateNamespace()) if metadata is None else metadata
        )
        self.coords = np.asarray(coords).reshape((-1, 3))

    @property
    def x(self) -> npt.NDArray[np.float64]:
        """

        :Examples:

        >>> cloud = PointCloud.read_from_path("tests/data/cloud.laz")
        >>> cloud.x.shape
        (28185,)

        :return: The array of x coordinates
        """
        return self.coords[:, 0]

    @property
    def y(self) -> npt.NDArray[np.float64]:
        """
        :return: The array of y coordinates
        """
        return self.coords[:, 1]

    @property
    def z(self) -> npt.NDArray[np.float64]:
        """
        :return: The array of z coordinates
        """
        return self.coords[:, 2]

    @staticmethod
    def read_from_path(path: PathLike) -> "PointCloud":
        """Reads the file, populate the point cloud and returns it

        :param path: path of the file to be read, s3 path are supported
        :return: the point cloud read
        """
        from geosat.cloud.io import read_from_path

        return read_from_path(path)

    @overload
    @staticmethod
    def open(path: PathLike, mode: Literal["r"] = "r") -> Reader: ...

    @overload
    @staticmethod
    def open(path: PathLike, mode: Literal["w"]) -> Writer: ...

    @staticmethod
    def open(path: PathLike, mode: Literal["r", "w"] = "r") -> Union[Reader, Writer]:
        """Opens the path with the specified mode
        see :func:`geosat.cloud.io.open_path`
        """
        from geosat.cloud.io import open_path

        return open_path(path, mode)

    def save(self, to_path: Optional[PathLike] = None) -> None:
        """Saves the point cloud.

        If the cloud was read using :func:`geosat.cloud.PointCloud.read_from_path`
        and to_path is not specified (None) then the original file wil be overwritten.

        :param to_path: where the file should be saved
        """
        from geosat.cloud.io import write_to_path

        if to_path is None:
            try:
                to_path = self.metadata["filepath"]
            except KeyError as exception:
                raise ValueError("This cloud was not opened from a path") from exception
        write_to_path(to_path, self)

    def bb_min(self) -> npt.NDArray[np.float64]:
        """
        :return: the min values for the coordinates
        """
        try:
            return np.min(self.coords, axis=0)
        except ValueError as exception:
            raise EmptyPointCloudException("bb_min") from exception

    def bb_max(self) -> npt.NDArray[np.float64]:
        """
        :return: the max values for the coordinates
        """
        try:
            return np.max(self.coords, axis=0)
        except ValueError as exception:
            raise EmptyPointCloudException("bb_max") from exception

    def __len__(self) -> int:
        return self.coords.shape[0]

    def __getitem__(
        self, subscript: Union[slice, np.ndarray, List[int]]
    ) -> "PointCloud":
        if isinstance(subscript, (slice, np.ndarray, list)):
            coords = self.coords[subscript]
            fields = {name: value[subscript] for name, value in self.fields.items()}
            return PointCloud(coords, fields, self.metadata)
        else:
            raise ValueError(
                f"Indexing in {self.__class__.__name__} is not supported "
                f"for object {subscript}"
            )

    def __getattr__(self, item: str) -> Any:
        try:
            return self.__getattribute__(item)
        except AttributeError:
            pass
        try:
            return self.__getattribute__("fields")[item]
        except KeyError as exception:
            raise AttributeError(
                f"This point cloud has no attribute or field named '{item}'"
            ) from exception

    def __repr__(self) -> str:
        return f"{self.__class__.__name__}({len(self)} points)"

    @classmethod
    def merge(cls, clouds: Iterable[Self]) -> "PointCloud":
        """Merges a list of homogeneous point clouds

        :param clouds: an iterable of point clouds to merge
        :return: a PointCloud instance containing the merge input clouds.
            The metadata is a deep copy of the first non-empty metadata encountered

        :Examples:

        >>> PointCloud.merge([])
        PointCloud(0 points)
        >>> PointCloud.merge([PointCloud([(0, 1, 2)])])
        PointCloud(1 points)
        >>> PointCloud.merge([PointCloud([(0, 1, 2)]), PointCloud([(3, 4, 5)])])
        PointCloud(2 points)
        """
        fields: Dict[str, List[np.ndarray]] = defaultdict(list)
        coord_list = []
        metadata = Metadata()
        for i, cloud in enumerate(clouds):
            if i == 0:
                metadata = deepcopy(cloud.metadata)
            else:
                different_fields = set(cloud.fields).symmetric_difference(fields)
                if different_fields:
                    raise HeterogeneousFieldsException(
                        "The following fields are not present in "
                        f"all clouds {different_fields}"
                    )
            coord_list.append(cloud.coords)
            for field_name, field in cloud.fields.items():
                fields[field_name].append(np.array(field))
        return PointCloud(
            np.concatenate(coord_list) if coord_list else np.empty((0, 3)),
            fields={
                field_name: np.concatenate(field_list)
                for field_name, field_list in fields.items()
            },
            metadata=metadata,
        )

    def __copy__(self) -> "PointCloud":
        return PointCloud(self.coords, self.fields, self.metadata)

    def __deepcopy__(self, memodict: Optional[Dict[Any, Any]] = None) -> "PointCloud":
        if memodict and id(self) in memodict:
            return memodict[id(self)]
        copied_cloud = PointCloud(
            deepcopy(self.coords, memodict),
            deepcopy(self.fields, memodict),
            deepcopy(self.metadata, memodict),
        )
        if memodict is None:
            memodict = {}
        if id(self) not in memodict:
            memodict[id(self)] = copied_cloud
        return copied_cloud

    def add_new_field(
        self,
        field_name: str,
        value: Union[int, float, complex, np.ndarray, Iterable] = 0,
        width: Optional[int] = None,
        dtype: type = np.int32,
    ) -> None:
        """Properly creates a new field if the field name is valid and not already
        used. The field created is a numpy array filled with 0 by default.
        The size of the field is the length of the cloud at its creation.
        Next to this method, the field can be accessed by the ``fields`` attribute
        or by its name as an attribute: ``pointcloud.new_field``.

        :param field_name: name of the field created. This name must not be already
            used and not equals to a method or an attribute name.
        :param value: value put to each case of the numpy array created.
        :param width: second dimension of the numpy array created.
        :param dtype: type of the numpy array.
        :raise FieldAlreadyExists: if the ``field_name`` already exists in the `
            `fields`` attribute.
        :raise InvalidFieldName: if the ``field_name`` is a method or an attribute name.
        """
        if field_name in self.fields:
            raise FieldAlreadyExists()
        if field_name in dir(self):
            raise InvalidFieldName(field_name)
        dimension = (len(self), width) if width is not None else (len(self),)
        self.fields[field_name] = np.full(
            shape=dimension, fill_value=value, dtype=dtype
        )
